if __name__ == "__main__":
    import argparse
    parser = argparse.ArgumentParser(description="Test parser")
    parser.add_argument("case", nargs="?", type=int, help="Chạy 1 case cụ thể (theo STT)")
    args = parser.parse_args()

    total_ok = total_fields = 0
    total_items = 0
    cases_run = 0

    for case_id, filename, raw_fn, zoom_fn in CASES:
        if args.case is not None and case_id != args.case:
            continue
        d = run_case(case_id, filename, raw_fn(), zoom_fn())
        ok, items = print_result(case_id, filename, d)
        total_ok += ok
        total_fields += len(ALL_FIELDS)
        total_items += items
        cases_run += 1

    if cases_run > 1:
        print(f"\n{'='*80}")
        print(f"TỔNG KẾT: {total_ok}/{total_fields} fields populated ({cases_run} cases)")
        pct = total_ok / total_fields * 100 if total_fields else 0
        print(f"Tỷ lệ: {pct:.1f}%")
        print(f"📦 Total items: {total_items}")
        print(f"{'='*80}")
